import { isVertical as isVerticalFn } from './orientation.js';
import type { Orientation } from '../../../../../core/types/orientation.js';
import { Dimensions } from '../../../types/dimensions.js';
import type { ChartLayoutLegendSizes } from '../types/chart-layout.js';
import {
  MAX_AUTO_RATIO_SIZE,
  MIN_LEGEND_HEIGHT,
  MIN_PLOT_SIZE,
  MIN_LEGEND_WIDTH,
} from '../types/constants.js';

export const calculateLegendSizeForAutoRatio = (
  orientation: Orientation,
  containerWidth: number,
  containerHeight: number,
  ratioBoundaries: ChartLayoutLegendSizes,
  candidateSizes?: number,
): Dimensions => {
  const isVertical = isVerticalFn(orientation);

  if (!candidateSizes) {
    const width = isVertical
      ? containerWidth
      : containerWidth * ratioBoundaries.minWidth;

    const height = isVertical
      ? containerHeight * ratioBoundaries.minHeight
      : containerHeight;

    return { width, height };
  }

  return isVertical
    ? calculateLegendAutoRatioInVertical(
        containerWidth,
        containerHeight,
        ratioBoundaries,
        candidateSizes,
      )
    : calculateBestLegendSizeInHorizontal(
        containerWidth,
        containerHeight,
        ratioBoundaries,
        candidateSizes,
      );
};

const calculateBestLegendSizeInHorizontal = (
  containerWidth: number,
  containerHeight: number,
  ratioBoundaries: ChartLayoutLegendSizes,
  candidateSize: number,
) => {
  const minAllowedRatio = MIN_LEGEND_WIDTH / containerWidth;
  const maxAllowedRatio = (containerWidth - MIN_PLOT_SIZE) / containerWidth;
  const minRatio = Math.min(ratioBoundaries.minWidth, minAllowedRatio);
  const maxRatio = Math.max(ratioBoundaries.maxWidth, maxAllowedRatio);
  const candidateRatio = candidateSize / containerWidth;

  const automaticRatio = Math.max(
    minRatio,
    Math.min(MAX_AUTO_RATIO_SIZE, candidateRatio, maxRatio),
  );

  const width = automaticRatio * containerWidth;
  const height = containerHeight;

  return { width, height };
};

const calculateLegendAutoRatioInVertical = (
  containerWidth: number,
  containerHeight: number,
  ratioBoundaries: ChartLayoutLegendSizes,
  candidateSize: number,
) => {
  const minAllowedRatio = MIN_LEGEND_HEIGHT / containerHeight;
  const maxAllowedRatio = (containerWidth - MIN_PLOT_SIZE) / containerHeight;
  const minRatio = Math.min(ratioBoundaries.minHeight, minAllowedRatio);
  const maxRatio = Math.max(ratioBoundaries.maxHeight, maxAllowedRatio);
  const candidateRatio = candidateSize / containerHeight;

  const automaticRatio = Math.max(
    minRatio,
    Math.min(MAX_AUTO_RATIO_SIZE, candidateRatio, maxRatio),
  );

  const width = containerWidth;
  const height = containerHeight * automaticRatio;

  return { width, height };
};
